import{_ as l,g as r,h as o,S as i}from"./chunks/vitepress-theme-teek.DI9UAdNZ.js";const c=JSON.parse('{"title":"用科学与迭代改善的方式推动减肥这件小事","description":"摘要总结：从“书生意气”到初入社会的“中年油腻”危机，一次健康警报让笔者开启了这场深刻的自我对话与行动。本文详细复盘了笔者从健康危机出发，通过四个阶段的循序渐进，成功实现体重管理的过程。区别于盲目跟风，笔者在实践中引入了目标拆解、数据监控（体脂秤指标）、跨领域经验迁移（如项目管理、时间管理）以及对不同策略（如控制饮食、加大无氧运动、尝试不吃主食）的辩证采纳。这不仅是一份减肥记录，更是一次用科学与迭代思维重构生活秩序、实现身心升级的实操指南。","frontmatter":{"date":"2022-09-12T08:16:00.000Z","title":"用科学与迭代改善的方式推动减肥这件小事","description":"摘要总结：从“书生意气”到初入社会的“中年油腻”危机，一次健康警报让笔者开启了这场深刻的自我对话与行动。本文详细复盘了笔者从健康危机出发，通过四个阶段的循序渐进，成功实现体重管理的过程。区别于盲目跟风，笔者在实践中引入了目标拆解、数据监控（体脂秤指标）、跨领域经验迁移（如项目管理、时间管理）以及对不同策略（如控制饮食、加大无氧运动、尝试不吃主食）的辩证采纳。这不仅是一份减肥记录，更是一次用科学与迭代思维重构生活秩序、实现身心升级的实操指南。","permalink":"/growth/weight-loss","coverImg":"https://insight-stack-1252300811.cos.ap-shanghai.myqcloud.com/img/cover/health_bg.png","top":true,"tags":["健康","运动"],"categories":["个人成长"]},"headers":[],"relativePath":"40.关于/30.成长随笔/20.减肥这件小事阶段随笔汇总.md","filePath":"40.关于/30.成长随笔/20.减肥这件小事阶段随笔汇总.md"}'),n={name:"40.关于/30.成长随笔/20.减肥这件小事阶段随笔汇总.md"};function s(a,t,e,g,d,p){return o(),r("div",null,[...t[0]||(t[0]=[i('<div style="display:none;" hidden="true" aria-hidden="true">Are you an LLM? You can read better optimized documentation at /40.关于/30.成长随笔/20.减肥这件小事阶段随笔汇总.md for this page in Markdown format</div><h1 id="用科学与迭代改善的方式推动减肥这件小事" tabindex="-1">用科学与迭代改善的方式推动减肥这件小事 <a class="header-anchor" href="#用科学与迭代改善的方式推动减肥这件小事" aria-label="Permalink to “用科学与迭代改善的方式推动减肥这件小事”">​</a></h1><blockquote><p><strong>摘要总结：</strong>从“书生意气”到初入社会的“中年油腻”危机，一次健康警报让笔者开启了这场深刻的自我对话与行动。本文详细复盘了笔者从健康危机出发，通过四个阶段的循序渐进，成功实现体重管理的过程。区别于盲目跟风，笔者在实践中引入了目标拆解、数据监控（体脂秤指标）、跨领域经验迁移（如项目管理、时间管理）以及对不同策略（如控制饮食、加大无氧运动、尝试不吃主食）的辩证采纳。这不仅是一份减肥记录，更是一次用科学与迭代思维重构生活秩序、实现身心升级的实操指南。</p></blockquote><h2 id="写在前面" tabindex="-1">写在前面 <a class="header-anchor" href="#写在前面" aria-label="Permalink to “写在前面”">​</a></h2><p>在经济快速发展的大背景下，一批又一批的大学生陆续走出校门进入社会大舞台。随着年龄与工作年限的增长，不知置身于其中的你是否感慨过自己在阅历上从“书生意气”渐渐演变为“四平八稳，游刃有余”；在身体养护方面从“身材无敌，年龄成迷，实打实一个传奇”演变为“中年油腻”。每个人多少都有自己的答案，笔者的答案是：走出校门进入社会后，当初对身边人有点苛刻，遇事火急火燎的自己逐渐得到了改善。身体却因原本在大学时没有怎么在意，经过长年累月地洗礼亮了一次小红灯。在康复期间，不止一次反思过之前的生活方式和入世模式，想一想 + 四处看一看后，慢慢也就开悟了，自然要启动一些改变尝试。</p><p>因此，也就有了这篇减肥这件小事阶段随笔汇总。一方面来总结下前几个阶段的操作，在操作的过程中也有跟老同学、老朋友互相请教过，希望其中的一些操作能对需要的人有一定的帮助；另一方面也想借助网络平台，收集一些建议，来改善不足的地方。</p><p>从整体来讲，减肥的原因有以下几点：</p><ul><li>【直接原因】身体康复了，也想通了一些事情，自然要向前看，去尝试改变。结合自身现状分析，体重降下去对工作、生活和一些出游都会呈现出是实实在在的益处。因此，减肥这件小事也就成了既充分也很有必要的事情，可做</li><li>【错误纠正】之前笔者因相信 【早饭吃得好，午饭少吃点，晚饭正常吃】可以缓解体重上升而选择大早上吃很多早餐。但由于早上 9 点左右才吃早饭，一个多月后惊奇地发现涨了 10 斤。因此，再不控制下体重，改变下生活方式，很快又要回到一心一意敲键盘，写的基本都是 bug ，业余对着电脑可以坐半天的固有模式了</li><li>【深层次原因】笔者业余也算是读了一定的书，刚好还有个小爱好：会关注国家大事（新时代农民工也需要通过学习来了解国家发展方向）。在读了近一年多的文章和书以后，越来越觉得：国家都能基于现状做出追赶发达国家到哪种程度的规划，并做出一系列调整动作。身为新时代的打工人，为啥就不能为自己后青春的下半场基于现状弄一个身体 + 见识启蒙 + 尝试实践，5到8年后让个人发展 + 修身 + 齐家达到某种程度的尝试。而这一切的前提是得有个健硕的身体 + 专业素养。因此，减肥这件小事也被注入了一点点小情怀，有了更高层次的追求</li><li>【榜样的影响】不管别人怎么看待“不追星、基本不打游戏，如果不是有特别感兴趣的话题也基本不扯闲淡”的奇葩，但笔者真的有这种偏向。笔者之前在大学时看过一些毛爷爷的相关书和电视剧后很膜拜，毛爷爷的思想和韬略真的足够学。笔者知道自己不可能达到那种高度，但伟人的很多习惯和优点适合当代年轻人学习，毕业季让即将出国的女神写了一幅字—— <code>《沁园春.雪》</code>，然后北上帝都。另外，前段时间看了毛爷爷在青年时期写下的 <code>《体育之研究》</code>。因此，<strong>在读了伟人的文章后，更从理论上理解了身体是根本的道理，即：体者，载知识之车而寓道德之舍也。体育一道，配德育与智育，而德智皆寄于体</strong>。</li></ul><p>直接原因 、错误纠正、深层次原因、榜样的影响都有了，也就需要考虑如何真真正正的进行尝试实践了。</p><h2 id="_1、前期准备" tabindex="-1">1、前期准备 <a class="header-anchor" href="#_1、前期准备" aria-label="Permalink to “1、前期准备”">​</a></h2><ul><li><strong>体脂秤一台</strong>，用于测量体重，并粗略了解 BMI、脂肪、肌肉、体型、基础代谢率、蛋白质等指标，以及正常体重应位于什么区间。</li><li><strong>与体脂秤对应的手机 APP</strong>，用于存储记录一些指标数据。在积累到一定数据量后，可以从时间维度上来了解体重走势，结合实际情况总结经验。</li><li><strong>瑜伽垫、哑铃、俯卧撑支架、卷腹等健身器材</strong>，用于锻炼上半身，做一些适合的无氧运动。</li></ul><h2 id="_2、第一阶段" tabindex="-1">2、第一阶段 <a class="header-anchor" href="#_2、第一阶段" aria-label="Permalink to “2、第一阶段”">​</a></h2><div class="note custom-block"><p class="title note-title custom-block-title">NOTE</p><p>第一阶段最重要的准则是：<strong>“管住嘴，迈开腿”</strong>。</p></div><ol><li>饮食限制时间和饭量</li></ol><blockquote><p>周末饮食保持正常</p></blockquote><ul><li><strong>早餐：</strong>自己做，保证 8 点到 8 点半期间吃早饭：一个包子 + 鸡蛋 + 燕麦。</li><li><strong>午餐：</strong>半份米饭 + 素菜 + 荤菜 or 轻食一份。</li><li><strong>晚餐：</strong><ul><li>中午若吃轻食，则下午正常吃饭</li><li>中午若正常吃饭，则下午吃轻食</li></ul></li></ul><ol start="2"><li>运动则选择每周至少三次在午休或晚休时间走一定的路，保证每日步数在5000 至 6000 步。</li><li>居家健身器材锻炼每周一到两次，不做过多要求。</li></ol><p>第一阶段的时间大概维持了一个月，<strong>体重获得了 8 斤左右的下降</strong>。期间最大的困难是<strong>新习惯的建立比较难，原有的生活习惯时不时进入大脑，只能硬着头皮控制自己</strong>。由于周末没有做比较大的限制，体重也因为周末饮食不当陆续出现反弹，在下降 5 斤 到 8 斤之间跳跃。所以，周六加了一个项目：<strong>下午拍篮球 1个小时 + 遛弯1个小时，如果还有体力，骑行 30 分钟到 1个小时</strong>。这个雷打不动的项目引入，<strong>不但解决了周末饮食的主要问题，对习惯的养成起到了一定的正向作用</strong>。</p><h2 id="_3、第二阶段" tabindex="-1">3、第二阶段 <a class="header-anchor" href="#_3、第二阶段" aria-label="Permalink to “3、第二阶段”">​</a></h2><p>本阶段主要<strong>吸收更多减肥方面的常识和习惯</strong>来调整减肥策略：</p><ul><li>在保持第一阶段建立的习惯基础上，<strong>加大锻炼强度</strong>： <ul><li>每周早上至少有三次居家 20 分钟的器材锻炼；</li><li>工作日每天必须在午休和晚休时间走一定的路，保证每日步数在 5000 至 6000 步；</li><li>周六锻炼继续保持，周日不做要求，根据称重数据适当奖励自己；</li></ul></li><li><strong>饮食调整</strong><ul><li>早餐：玉米 + 鸡蛋 + 燕麦；</li><li>午餐和晚餐不做大改变，米饭改为减半；</li></ul></li><li>平时注重多与同事、同学和朋友沟通，<strong>向一些有经验的人请教方法</strong>；</li></ul><p>这个阶段更注重强化减肥这件小事的目标合理性，以及其收益。看一些比较正向的文章，饥饿时转移注意力。业余跟老伙计保持财商与减肥方面的学习沟通，并强制每两天内必须在朋友圈至少打卡一次。</p><p>就这样，第二阶段的时间也大概维持了一个月，体重再次获得了 5 斤下降。<strong>在第二阶段快结束时遇到了体重基本不再下降，甚至一周基本保持不变的情况</strong>，经过分析体重外的指标发现：<strong>肌肉与脂肪指标数据不稳，两者基本保持此消彼长的竞争状态。基础代谢率有时达到标准状态，有时不达标</strong>。</p><p>减肥这件事情可大可小，笔者在第二阶段时还属于身体管理小白，<strong>体重维持不变后基本不晓得怎么搞了</strong>。在这期间，从微信读书上找了本书，业余翻了翻，其中大部分的讲解或许对很多人有帮助，但对于笔者存在很多不可行之处。这个时候也想过在健身房报个班，每次想去健身房看看时，就会想到在学校毕业季曾因锻炼不当锻炼后疼了很久，后来健身房也就成了几个已经找到工作的懒人的澡堂子啦。<strong>这一次比较幸运，因为一次偶然的事情出现后，从大佬口中得知他在减体重时尝试过不吃主食。</strong></p><p>不吃主食这个事情笔者个人<strong>之前没有尝试过</strong>，听起来在一定时间内或许不会有问题，但长期看对身体可能存在某些不好的地方。<strong>在查过一些资料文章后，笔者还是决定在第三阶段试试一段时间</strong>。</p><h2 id="_4、第三阶段" tabindex="-1">4、第三阶段 <a class="header-anchor" href="#_4、第三阶段" aria-label="Permalink to “4、第三阶段”">​</a></h2><p>第三阶段主要通过以下几个方面来继续把减肥这件小事执行下去：</p><ol><li>进一步强化把握最终目标，<strong>引入平时处理项目的经验来管理、拆解目标</strong>：将总目标拆解为每 6 天至少减重 1 斤，每月体重下降至少 5 斤。另外，把日常看的时间管理相关书籍，也尝试应用于工作、生活和减肥这件小事上。</li><li>在保持第一和二阶段建立的习惯基础上，继续<strong>加大训练强度</strong>： <ul><li>工作日每天早上在早饭前，进行 20-30分钟的器材锻炼；</li><li>工作日每天至少下一次楼梯，不乘坐电梯；</li><li>工作日每天午休和晚休走一定的路，保证每天步数在 6000 到 8000 步；</li><li>每周两次使用小区或公司健身房器材进行 30 - 40 分钟的无氧运动；</li><li>周六锻炼继续保持，周日不做要求，但控制饮食，多吃些蔬菜和水果；</li></ul></li><li>饮食调整（工作日午饭和晚饭最多吃两天主食，且主食为半份糙米饭）</li></ol><blockquote><p>🥗 饮食表</p></blockquote><table tabindex="0"><thead><tr><th>时段</th><th>可选项</th></tr></thead><tbody><tr><td><strong>早餐</strong></td><td>玉米/红薯 + 鸡蛋 + 低脂牛奶燕麦<br>玉米/红薯 + 鸡蛋羹 + 低脂牛奶燕麦</td></tr><tr><td><strong>周末早饭</strong></td><td>玉米/红薯/豆腐 + 鸡蛋羹 + 低脂牛奶燕麦</td></tr><tr><td><strong>午餐/晚餐</strong></td><td>素菜 + 小份轻食（含少部分主食）<br>鱼 + 素菜（不吃主食/半份糙米饭）<br>轻食一份</td></tr><tr><td><strong>周末午餐/晚饭尝试</strong></td><td>使用鸡胸肉、扇贝肉、胡萝卜、西蓝花、玉米等食材搭配做一道简版轻食 + 燕麦/少量水饺<br>使用三文鱼、巴沙鱼片、虾仁等食材做一道菜或汤 + 燕麦/少量水饺<br>使用青椒、青菜、黄瓜、木耳、鸡蛋等食材做一到两道家常菜 + 燕麦/少量水饺</td></tr></tbody></table><p>第三阶段也是大概维持了一个月，一直到 8 月底，<strong>在吃极少量主食和加大运动量的坚持下，体重又获得了 5—6斤的下降，虽然会呈现少部分波动，但基本能够控制住整体继续下降的趋势</strong>。这一阶段，对笔者来说取得了一些比较大的进步，这些进步不局限于减肥这件小事上：</p><ul><li>尝试把一些别的领域或事务的经验迁移、应用在减肥这件小事上，<strong>强化了一种万变不离其宗，万物有规则可循的思维方式</strong>；</li><li>学会接受并尝试别人的建议，但不会一味按照别人的建议来，<strong>要结合实际情况具体处理</strong>；</li><li><strong>自身厨艺进一步获得了提升机会，对做饭这件小事也起到了促进作用</strong>，在做饭花样和做饭花费时间上的把握更加精确；</li></ul><h2 id="_5、第四阶段-2021-09" tabindex="-1">5、第四阶段（2021.09） <a class="header-anchor" href="#_5、第四阶段-2021-09" aria-label="Permalink to “5、第四阶段（2021.09）”">​</a></h2><p>第四阶段，即现阶段（9月份），正在通过以下几种方式来将减肥这件小事继续：</p><ol><li>坚持执行拆解后的目标：<strong>每 6 天至少减重 1 斤，每月体重下降至少 5 斤</strong>。</li><li>在保持第一、二、三阶段建立的习惯基础上，<strong>继续加大训练强度</strong>： <ul><li>工作日每天早上在早饭前，进行 30 分钟的器材锻炼</li><li>工作日每天至少下一次楼梯，不乘坐电梯</li><li>工作日每天午休和晚休走一定的路，保证每天步数在 8000 步以上。<strong>周末不做限制，步数尽量不要超过10000</strong>。做限制的原因：<strong>走路只是维持正常的有氧运动，其收益不一定比一段时间强有力的无氧运动有效果，且容易影响膝盖，不能继续增加</strong>。</li><li>每周两到三次使用小区或公司健身房器材进行 30 - 40 分钟的无氧运动</li><li>周六拍篮球的场地和时间不再继续做限制，<strong>周六和周日侧重进行分组的无氧运动来加强锻炼</strong>，只要保证消耗 &gt;= 摄入量 即可。</li></ul></li><li>饮食微调：整体保持第三阶段的执行，在尝试去观察改善 <ul><li>工作日继续多去不同的餐区吃饭，观察同事们、工友吃什么，以及餐区大概都是做什么饭菜；</li><li>周末做饭，启动使用<strong>橄榄油</strong>，橄榄油的具体效用这里不做介绍，想必很多人已经知晓，确实有点小贵，幸亏当初学习培养财商，卖一部分基金还是可以消费橄榄油的；</li></ul></li><li><strong>继续积累常识</strong>：保持业余通过看书或文章，与同事、同学和朋友交流等方式了解一些小常识。每周阅读1- 2篇专刊会 APP 中关于运动健康方面的杂志文章，了解一些常识。</li><li>关注并优化体重秤日常的 总体重、基础代谢率、肌肉、水分等指标： <ul><li>总体重需要呈现下降确实；</li><li>肌肉占比、基础代谢率、水分三个指标优化至稳步停留在标准范围内；</li></ul></li></ol><p>现阶段也需要维持一个月，如果出现反弹情况，甚至需要花费两个月。当前目标、运动、饮食调整基本正常执行，指标与业余学习和交流后续希望以周为单位推进。</p><h2 id="结尾" tabindex="-1">结尾 <a class="header-anchor" href="#结尾" aria-label="Permalink to “结尾”">​</a></h2><p>以上仅仅是结合个人实践的记录，还需要进一步实验下去，估计未必适合每一个人。我们迈入社会后，难免会看到社会用各种属性来评判一个人。在这所更大的学校中，笔者感觉自己属于转变比较慢的一批人。</p><p>之前很多同学和朋友甚至早已融入到社会之中，而笔者个人觉得自己从 2020 年才转变为社会人。<strong>快与慢只是表象，只要能把握住规则的脉搏，结合自己的习惯和节奏也可以慢慢上轨，纵然中间有一些偏差或挫折，但触底反弹，反省自身的不足会有新的领悟境界</strong>。</p>',39)])])}const _=l(n,[["render",s]]);export{c as __pageData,_ as default};
